#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int X,Y,Z; scanf("%d %d %d",&X,&Y,&Z);
        printf("%d\n", X*Y*Z);
    }
    return 0;
}

